use super::*;
use crate::provider::{
    mock::MockLlmProvider,
    types::{ChatMessage, ChatOptions, ChatRequest, ContentBlock, FinishReason, StreamEvent, TokenUsage, ToolCall},
    AgentEvent, AgentEventReceiver, AgentEventSender, agent_event_channel,
};
use futures::StreamExt;
use serde_json::json;

fn make_request(messages: Vec<ChatMessage>) -> ChatRequest {
    ChatRequest {
        messages,
        tools: vec![],
        options: ChatOptions::default(),
    }
}

#[tokio::test]
async fn collect_stream_text_only() {
    let events = vec![
        StreamEvent::Start,
        StreamEvent::TextChunk("Hello ".into()),
        StreamEvent::TextChunk("world".into()),
        StreamEvent::End {
            finish_reason: FinishReason::Stop,
            usage: Some(TokenUsage { input_tokens: 5, output_tokens: 3, cache_read_tokens: None }),
        },
    ];
    let mock = MockLlmProvider::new().with_stream(events);
    let stream = mock.chat_stream(make_request(vec![
        ChatMessage::User(vec![ContentBlock::Text("hi".into())])
    ])).await.unwrap();

    let (tx, rx) = agent_event_channel(32);
    let (cancel_tx, cancel_rx) = futures::channel::oneshot::channel::<()>();
    let mut cancel = cancel_rx.fuse();

    let (text, tool_calls) = collect_and_emit_stream(stream, &tx, &mut cancel).await.unwrap();

    assert_eq!(text.unwrap(), "Hello world");
    assert!(tool_calls.is_empty());
    drop(cancel_tx);
    drop(tx);

    // Verify events were sent to the channel
    let mut received = vec![];
    while let Ok(ev) = rx.try_recv() {
        received.push(ev);
    }
    assert!(received.iter().any(|e| matches!(e, AgentEvent::TextChunk(_))));
    assert!(received.iter().any(|e| matches!(e, AgentEvent::TokenUsage(_))));
}

#[tokio::test]
async fn collect_stream_with_tool_call() {
    let tc = ToolCall { id: "call_1".into(), name: "Grep".into(), input: json!({}) };
    let events = vec![
        StreamEvent::Start,
        StreamEvent::ToolCallReady(tc),
        StreamEvent::End {
            finish_reason: FinishReason::ToolUse,
            usage: None,
        },
    ];
    let mock = MockLlmProvider::new().with_stream(events);
    let stream = mock.chat_stream(make_request(vec![
        ChatMessage::User(vec![ContentBlock::Text("grep for foo".into())])
    ])).await.unwrap();

    let (tx, _rx) = agent_event_channel(32);
    let (_cancel_tx, cancel_rx) = futures::channel::oneshot::channel::<()>();
    let mut cancel = cancel_rx.fuse();

    let (text, tool_calls) = collect_and_emit_stream(stream, &tx, &mut cancel).await.unwrap();

    assert!(text.is_none());
    assert_eq!(tool_calls.len(), 1);
    assert_eq!(tool_calls[0].name, "Grep");
}

#[tokio::test]
async fn collect_stream_cancel_returns_cancelled() {
    use crate::provider::ProviderError;
    let events = vec![
        StreamEvent::Start,
        StreamEvent::TextChunk("partial...".into()),
        // No End — stream would hang if not cancelled
    ];
    let mock = MockLlmProvider::new().with_stream(events);
    let stream = mock.chat_stream(make_request(vec![
        ChatMessage::User(vec![ContentBlock::Text("hi".into())])
    ])).await.unwrap();

    let (tx, _rx) = agent_event_channel(32);
    let (cancel_tx, cancel_rx) = futures::channel::oneshot::channel::<()>();
    let mut cancel = cancel_rx.fuse();

    // Cancel immediately before polling
    cancel_tx.send(()).unwrap();

    let result = collect_and_emit_stream(stream, &tx, &mut cancel).await;
    assert!(matches!(result, Err(ProviderError::Cancelled)));
}

#[tokio::test]
async fn collect_stream_provider_error_propagates() {
    use crate::provider::ProviderError;
    let error_stream: crate::provider::ChatStream = {
        use futures::stream;
        Box::pin(stream::iter(vec![
            Ok(StreamEvent::Start),
            Err(ProviderError::Remote {
                provider: "openai".into(),
                code: Some("server_error".into()),
                message: "Internal error".into(),
            }),
        ]))
    };

    let (tx, _rx) = agent_event_channel(32);
    let (_cancel_tx, cancel_rx) = futures::channel::oneshot::channel::<()>();
    let mut cancel = cancel_rx.fuse();

    let result = collect_and_emit_stream(error_stream, &tx, &mut cancel).await;
    assert!(matches!(result, Err(ProviderError::Remote { .. })));
}

use super::*;
use crate::provider::types::{ChatMessage, ContentBlock, ToolCall, ToolResultContent};
use serde_json::json;

fn system() -> ChatMessage {
    ChatMessage::System("sys".into())
}
fn user(text: &str) -> ChatMessage {
    ChatMessage::User(vec![ContentBlock::Text(text.into())])
}
fn assistant_text(text: &str) -> ChatMessage {
    ChatMessage::Assistant { text: Some(text.into()), tool_calls: vec![] }
}
fn assistant_tools(tools: Vec<ToolCall>) -> ChatMessage {
    ChatMessage::Assistant { text: None, tool_calls: tools }
}
fn tool_results(ids: &[&str]) -> ChatMessage {
    let blocks = ids
        .iter()
        .map(|id| ContentBlock::ToolResult {
            tool_use_id: (*id).to_owned(),
            content: ToolResultContent::Text("result".into()),
            is_error: false,
        })
        .collect();
    ChatMessage::User(blocks)
}

