}

#[test]
fn trim_keeps_tool_call_pair_together() {
    // Assistant(tool_calls) + User(tool_results) must be kept as an indivisible pair
    let tc = ToolCall { id: "c1".into(), name: "Grep".into(), input: json!({}) };
    let history = vec![
        system(),
        user("first query"),
        assistant_text("first answer"),
        user("second query"),
        assistant_tools(vec![tc]),
